import React, { useState, useContext } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import { GoogleLogin } from '@react-oauth/google';
import { jwtDecode } from "jwt-decode";
import Header from '../components/common/Header';
import Navbar from '../components/common/Navbar';
import Footer from '../components/common/Footer';

const Login = () => {
  const [activeTab, setActiveTab] = useState('login');
  const [form, setForm] = useState({ name: '', email: '', password: '' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();
  const { login, register } = useContext(AuthContext);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    if (!form.email || !form.password) return setError('Vui lòng nhập email và mật khẩu');
    setLoading(true);
    const result = await login(form.email, form.password);
    setLoading(false);
    result?.success ? navigate('/') : setError(result?.message || 'Đăng nhập thất bại');
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    setError('');
    if (!form.name || !form.email || !form.password) return setError('Vui lòng nhập đủ thông tin');
    setLoading(true);
    const result = await register(form.name, form.email, form.password);
    setLoading(false);
    result?.success ? navigate('/') : setError(result?.message || 'Đăng ký thất bại');
  };

  // ✅ Đăng nhập bằng Google
  const handleGoogleLogin = (response) => {
   const user = jwtDecode(response.credential);
    console.log("Thông tin người dùng Google:", user);
    alert(`Chào ${user.name} 🌸`);
    // 👉 Nếu muốn kết nối backend: gửi token user.email tới server để tự tạo tài khoản
  };

  return (
    <div className="flex flex-col min-h-screen bg-[#faf8f6]">
      <Header />
      <Navbar />
      <main className="flex flex-1 items-center justify-center bg-[#faf8f6] py-12 px-4">
  <div className="w-full max-w-md bg-white shadow-md rounded-2xl p-8 border border-[#f1e3df]">
    <h2 className="text-center text-2xl font-semibold text-[#e06c7f] mb-6">
      {activeTab === 'login' ? 'Đăng nhập' : 'Đăng ký'}
    </h2>

    {/* Tabs */}
    <div className="flex mb-6 border-b">
      {['login', 'register'].map((tab) => (
        <button
          key={tab}
          className={`flex-1 py-3 font-medium transition ${
            activeTab === tab
              ? 'text-[#e06c7f] border-b-2 border-[#e06c7f]'
              : 'text-gray-500 hover:text-[#e06c7f]'
          }`}
          onClick={() => {
            setActiveTab(tab);
            setError('');
          }}
        >
          {tab === 'login' ? 'Đăng nhập' : 'Đăng ký'}
        </button>
      ))}
    </div>

    {error && (
      <div className="bg-red-100 text-red-700 p-3 rounded mb-4 text-sm text-center">
        {error}
      </div>
    )}

    {/* Form nội dung */}
    {activeTab === 'login' ? (
      <form onSubmit={handleLogin}>
        <input
          type="email"
          name="email"
          placeholder="Email"
          value={form.email}
          onChange={handleChange}
          className="w-full mb-3 p-3 border rounded-lg focus:ring-2 focus:ring-[#e06c7f]"
        />
        <input
          type="password"
          name="password"
          placeholder="Mật khẩu"
          value={form.password}
          onChange={handleChange}
          className="w-full mb-4 p-3 border rounded-lg focus:ring-2 focus:ring-[#e06c7f]"
        />
        <button
          type="submit"
          disabled={loading}
          className="w-full bg-[#e06c7f] text-white py-3 rounded-lg hover:bg-[#d35c70] transition"
        >
          {loading ? 'Đang đăng nhập...' : 'Đăng nhập'}
        </button>
      </form>
    ) : (
      <form onSubmit={handleRegister}>
        <input
          type="text"
          name="name"
          placeholder="Họ và tên"
          value={form.name}
          onChange={handleChange}
          className="w-full mb-3 p-3 border rounded-lg focus:ring-2 focus:ring-[#e06c7f]"
        />
        <input
          type="email"
          name="email"
          placeholder="Email"
          value={form.email}
          onChange={handleChange}
          className="w-full mb-3 p-3 border rounded-lg focus:ring-2 focus:ring-[#e06c7f]"
        />
        <input
          type="password"
          name="password"
          placeholder="Mật khẩu"
          value={form.password}
          onChange={handleChange}
          className="w-full mb-4 p-3 border rounded-lg focus:ring-2 focus:ring-[#e06c7f]"
        />
        <button
          type="submit"
          disabled={loading}
          className="w-full bg-[#e06c7f] text-white py-3 rounded-lg hover:bg-[#d35c70] transition"
        >
          {loading ? 'Đang đăng ký...' : 'Đăng ký tài khoản'}
        </button>
      </form>
    )}
  </div>
</main>

      <Footer />
    </div>
  );
};

export default Login;
